import React, { useState, useEffect } from 'react';

function AvatarPreview({ user, measurements, outfit, onBack }) {
  const [svgContent, setSvgContent] = useState('');
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      const response = await fetch(`http://localhost:3000/api/users/${user.id}/profile`);
      const data = await response.json();
      setProfile(data);
      generateAvatar(data, measurements);
    } catch (error) {
      console.error('Error fetching profile:', error);
      generateAvatar(null, measurements);
    } finally {
      setLoading(false);
    }
  };

  const getSkinTone = (tone) => {
    const tones = {
      'Fair': '#fdbcb4',
      'Light': '#f4a582',
      'Medium': '#d4956e',
      'Tan': '#c9915d',
      'Deep': '#9d6f47',
    };
    return tones[tone] || '#f4a460';
  };

  const generateAvatar = (profileData, meas) => {
    const chest = meas?.chest || 36;
    const scale = Math.max(0.7, Math.min(1.5, chest / 36));
    const skinColor = getSkinTone(profileData?.profile?.skinTone || 'Medium');
    const bodyType = profileData?.profile?.bodyType || 'Average';

    // Adjust body width based on body type
    let widthMultiplier = 1;
    if (bodyType === 'Petite') widthMultiplier = 0.8;
    if (bodyType === 'Plus-size') widthMultiplier = 1.3;
    if (bodyType === 'Tall') widthMultiplier = 0.9;

    const bodyWidth = 60 * scale * widthMultiplier;
    const bodyHeight = 120 * scale;

    const svg = `<svg width="100%" height="100%" viewBox="0 0 400 600" xmlns="http://www.w3.org/2000/svg">
      <defs>
        <linearGradient id="bodyGradient" x1="0%" y1="0%" x2="100%" y2="0%">
          <stop offset="0%" style="stop-color:${skinColor};stop-opacity:0.9" />
          <stop offset="50%" style="stop-color:${skinColor};stop-opacity:1" />
          <stop offset="100%" style="stop-color:${skinColor};stop-opacity:0.85" />
        </linearGradient>
        <radialGradient id="headGradient" cx="40%" cy="40%">
          <stop offset="0%" style="stop-color:#fff9e6;stop-opacity:0.3" />
          <stop offset="100%" style="stop-color:#000;stop-opacity:0.1" />
        </radialGradient>
        <linearGradient id="shirtGradient" x1="0%" y1="0%" x2="0%" y2="100%">
          <stop offset="0%" style="stop-color:#8B4789;stop-opacity:1" />
          <stop offset="100%" style="stop-color:#6B2F69;stop-opacity:1" />
        </linearGradient>
      </defs>

      <!-- Background -->
      <rect width="400" height="600" fill="#f5f5f5"/>

      <!-- Shadow -->
      <ellipse cx="200" cy="520" rx="80" ry="20" fill="#00000015"/>

      <!-- Head -->
      <circle cx="200" cy="100" r="45" fill="${skinColor}"/>
      <circle cx="200" cy="100" r="45" fill="url(#headGradient)"/>

      <!-- Eyes -->
      <circle cx="185" cy="95" r="6" fill="#333"/>
      <circle cx="215" cy="95" r="6" fill="#333"/>
      <circle cx="187" cy="93" r="2" fill="#fff"/>
      <circle cx="217" cy="93" r="2" fill="#fff"/>

      <!-- Nose -->
      <path d="M 200 95 L 200 110" stroke="${skinColor}" stroke-width="2" fill="none"/>

      <!-- Mouth -->
      <path d="M 190 120 Q 200 125 210 120" stroke="#d4756d" stroke-width="2" fill="none"/>

      <!-- Neck -->
      <rect x="${200 - 20 * scale}" y="140" width="${40 * scale}" height="15" fill="${skinColor}"/>

      <!-- Shirt/Top -->
      <rect x="${200 - bodyWidth/2}" y="155" width="${bodyWidth}" height="${bodyHeight}" rx="15" fill="url(#shirtGradient)" stroke="#6B2F69" stroke-width="2"/>
      <rect x="${200 - bodyWidth/2 + 5}" y="160" width="${bodyWidth - 10}" height="10" fill="#fff" opacity="0.2"/>

      <!-- Arms -->
      <ellipse cx="${200 - bodyWidth/2 - 30}" cy="180" rx="20" ry="35" fill="${skinColor}"/>
      <ellipse cx="${200 + bodyWidth/2 + 30}" cy="180" rx="20" ry="35" fill="${skinColor}"/>

      <!-- Hands -->
      <circle cx="${200 - bodyWidth/2 - 30}" cy="220" r="15" fill="${skinColor}"/>
      <circle cx="${200 + bodyWidth/2 + 30}" cy="220" r="15" fill="${skinColor}"/>

      <!-- Pants -->
      <rect x="${200 - bodyWidth/2 + 5}" y="275" width="${(bodyWidth - 10)/2 - 3}" height="140" fill="#333"/>
      <rect x="${200 + 3}" y="275" width="${(bodyWidth - 10)/2 - 3}" height="140" fill="#222"/>

      <!-- Shoes -->
      <ellipse cx="${200 - (bodyWidth - 10)/4}" cy="425" rx="25" ry="15" fill="#1a1a1a"/>
      <ellipse cx="${200 + (bodyWidth - 10)/4}" cy="425" rx="25" ry="15" fill="#1a1a1a"/>

      <!-- 3D Shading on body -->
      <rect x="${200 + bodyWidth/2 - 10}" y="155" width="10" height="${bodyHeight}" rx="10" fill="#00000015"/>

      <!-- Text -->
      <text x="200" y="550" text-anchor="middle" font-size="18" font-weight="bold" fill="#333">Your Avatar</text>
      <text x="200" y="575" text-anchor="middle" font-size="12" fill="#666">${bodyType} • ${profileData?.profile?.skinTone || 'Not set'}</text>
    </svg>`;

    setSvgContent(svg);
  };

  if (loading) return <div className="App"><div className="card"><p>Loading avatar...</p></div></div>;

  return (
    <div className="App avatar-preview">
      <div className="navbar">
        <h1>👤 Your Avatar</h1>
        <button onClick={onBack} className="back-btn">← Back</button>
      </div>
      <div className="avatar-container">
        <div className="avatar-display" dangerouslySetInnerHTML={{ __html: svgContent }} />
        <div className="avatar-info">
          <h2>Your Profile</h2>
          {profile && (
            <div className="info-box">
              <p><strong>Body Type:</strong> {profile.profile?.bodyType || 'Not set'}</p>
              <p><strong>Skin Tone:</strong> {profile.profile?.skinTone || 'Not set'}</p>
              <p><strong>Style:</strong> {profile.profile?.style || 'Not set'}</p>
              <hr style={{margin: '15px 0', border: 'none', borderTop: '1px solid #ddd'}} />
              <p><strong>Chest:</strong> {profile.measurements?.chest || 'Not set'}"</p>
              <p><strong>Waist:</strong> {profile.measurements?.waist || 'Not set'}"</p>
              <p><strong>Hips:</strong> {profile.measurements?.hips || 'Not set'}"</p>
              <p><strong>Height:</strong> {profile.measurements?.height || 'Not set'}'</p>
            </div>
          )}
          <button onClick={onBack} className="btn-primary" style={{width: '100%', marginTop: '20px'}}>← Back to Dashboard</button>
        </div>
      </div>
    </div>
  );
}

export default AvatarPreview;
